section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/freelancer-weekly-report-template.json",
  "title": "Freelancer Weekly Report Template",
  "type": "object",
  "required": [
    "artefact_id",
    "report_week",
    "shipped",
    "next",
    "risks",
    "asks",
    "client",
    "cadence_anchor",
    "status",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "report_week": {
      "type": "string",
      "description": "ISO week (YYYY-Www) the report covers",
      "minLength": 1
    },
    "shipped": {
      "type": "array",
      "description": "list of {item, evidence} pairs \u2014 each evidence is a PR URL, ticket id, or commit hash",
      "minItems": 1
    },
    "next": {
      "type": "array",
      "description": "list of {item, owner, deadline} for the next cycle",
      "minItems": 1
    },
    "risks": {
      "type": "array",
      "description": "list of {risk, mitigation, owner} entries",
      "minItems": 1
    },
    "asks": {
      "type": "array",
      "description": "list of {ask, recipient} pairs \u2014 empty array means no blockers",
      "minItems": 1
    },
    "client": {
      "type": "string",
      "description": "named client (organisation + primary contact)",
      "minLength": 1
    },
    "cadence_anchor": {
      "type": "string",
      "description": "fixed day-of-week + time the report ships every week",
      "minLength": 1
    }
  },
  "additionalProperties": false
}
